async (params, browser) => {
  // Open page
  await browser.open(`https://huggingface.co/datasets/${params.dataset_id}`)

  // Wait for content
  await browser.waitForSelector('.prose, h1, main', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim()||''; const tags = Array.from(document.querySelectorAll('a[href*="/datasets?"]')).slice(0,10).map(t=>t.textContent.trim()); const licenseEl = document.querySelector('a[href*="choosealicense"], a[href*="/datasets?license="]'); const license = licenseEl?.textContent?.trim()||''; const card = document.querySelector('.prose')?.innerText?.substring(0,3000)||''; const dlEl = document.querySelector('[title*="download"], [title*="Download"]'); const downloads = dlEl?.textContent?.trim()||''; return { title, tags, license, downloads, card_content: card, url: window.location.href }`)

  return page_data
}
